    if (lang !== prevLang) {
        if (lang) {
            localStorage.setItem('recognitionLang', lang);
        } else {
            localStorage.removeItem('recognitionLang');
        }
        // Re-init recognition so new language takes effect immediately
        if (!isListening) initRecognition();
